            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/purchasing"]""",
            Tags = """["purchasing","rfq","procurement","walkthrough"]""",
            ContentJson = """{"appRoute":"/purchasing","startButtonLabel":"Tour Purchasing","steps":[{"element":"[data-testid='new-rfq-btn']","popover":{"title":"New RFQ Button","description":"Click here to create a Request for Quote. You select a Part, enter the Quantity and Required Date, and optionally a Response Deadline, Description, and Special Instructions. New RFQs start in Draft status so you can refine them before sending.","side":"bottom"}},{"element":".filters-bar app-input","popover":{"title":"Search RFQs","description":"Search across RFQ number, part number, and part description. Type to narrow the list below; the placeholder reads 'Search RFQs...'.","side":"bottom"}},{"element":".filters-bar app-select","popover":{"title":"Status Filter","description":"Filter RFQs by status: Draft, Sent, Receiving, Evaluating, Awarded, Cancelled, or Expired (plus All Statuses). Each status renders as a color-coded chip in the table.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"RFQs Table","description":"Each row is an RFQ: RFQ #, Part, Description, Qty, a color-coded Status chip, Vendors (invited count), Received (responses count), Required date, Deadline, and Created. Click any row to open the RFQ detail dialog.","side":"top"}},{"element":"app-data-table","popover":{"title":"RFQ Detail — Send to Vendors","description":"Clicking a row opens the detail dialog. It shows the part, quantity, required date, status, and any responses. While the RFQ is Draft or Sent, the Send to Vendors action opens a multi-select of vendors (excluding those already invited) so you can request quotes. Each invited vendor gets a Pending response and the RFQ moves to Sent.","side":"top"}},{"element":"app-data-table","popover":{"title":"RFQ Detail — Record Response","description":"While the RFQ is Sent or Receiving, the Record Response action lets you enter a vendor's quote: Unit Price, Lead Time (days), MOQ, Tooling Cost, Quote Valid Until, and Notes. Only the vendor is required. Recording a response marks that vendor's response Received so it can be compared and awarded.","side":"top"}},{"element":"app-data-table","popover":{"title":"RFQ Detail — Compare and Award","description":"The vendor responses table lists each vendor's quote side by side. Click Award on the winning Received response to confirm, set the RFQ to Awarded, and generate a linked Purchase Order. The other responses become Not Awarded, and a View PO link appears. Award is one-way and the only button that creates a PO from an RFQ.","side":"top"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
