            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 6,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/purchasing"]""",
            Tags = """["purchasing","rfq","procurement","reference"]""",
            ContentJson = """{"title":"Purchasing Field Reference","groups":[{"heading":"RFQ Form Fields (Create / Edit Dialog)","items":[{"label":"Part (required)","value":"Select dropdown. The part to source, shown as 'PartNumber — Description'. Required. data-testid: rfq-part"},{"label":"Quantity (required)","value":"Number input. The quantity needed. Required, minimum 1. data-testid: rfq-quantity"},{"label":"Required Date (required)","value":"Datepicker. When the part is needed by. Required. data-testid: rfq-required-date"},{"label":"Response Deadline (optional)","value":"Datepicker. When vendors must respond by. Optional. data-testid: rfq-response-deadline"},{"label":"Description (optional)","value":"Textarea, 3 rows. General notes about the RFQ. Optional. data-testid: rfq-description"},{"label":"Special Instructions (optional)","value":"Textarea, 3 rows. Special handling or quoting requirements. Optional. data-testid: rfq-special-instructions"}]},{"heading":"Record Vendor Response Fields","items":[{"label":"Vendor (required)","value":"Select. Only vendors with a Pending response on this RFQ appear. The only required field on this form."},{"label":"Unit Price (optional)","value":"Number input. The vendor's quoted unit price."},{"label":"Lead Time (days) (optional)","value":"Number input. Quoted lead time in days."},{"label":"Minimum Order Quantity (optional)","value":"Number input. The vendor's MOQ for this part."},{"label":"Tooling Cost (optional)","value":"Number input. Any one-time tooling charge in the quote."},{"label":"Quote Valid Until (optional)","value":"Datepicker. How long the quote stands."},{"label":"Notes (optional)","value":"Textarea. Free-form notes on the quote."}]},{"heading":"Send to Vendors","items":[{"label":"Vendor multi-select","value":"Pick one or more vendors to request quotes from. Vendors already invited to this RFQ are excluded from the list."},{"label":"Send button","value":"Sends the RFQ to the selected vendors. Disabled when no vendors are selected. Each invited vendor gets a Pending response and the RFQ moves to Sent."}]},{"heading":"RFQ Statuses","items":[{"label":"Draft (gray/muted chip)","value":"Created but not yet sent to any vendor. Initial status; editable. Can send to vendors from here."},{"label":"Sent (blue/info chip)","value":"Sent to one or more vendors. Each invited vendor has a Pending response. Can record responses and invite more vendors."},{"label":"Receiving (teal/primary chip)","value":"Quotes are being collected. Responses can still be recorded."},{"label":"Evaluating (amber/warning chip)","value":"Responses are being compared before awarding."},{"label":"Awarded (green/success chip)","value":"Awarded to one vendor's response; award timestamp recorded and a Purchase Order generated. Effectively terminal."},{"label":"Cancelled (red/error chip)","value":"The RFQ was cancelled. Terminal status."},{"label":"Expired (gray/muted chip)","value":"The RFQ passed its window without being awarded. Terminal status."}]},{"heading":"Vendor Response Statuses","items":[{"label":"Pending","value":"The vendor was invited but has not quoted yet. Only Pending vendors appear in the Record Response vendor list."},{"label":"Received","value":"A quote has been recorded for this vendor. Only Received responses can be awarded."},{"label":"Declined","value":"The vendor declined to quote."},{"label":"Awarded (green chip)","value":"This response won the RFQ; the linked Purchase Order is for this vendor."},{"label":"Not Awarded (amber chip)","value":"Another response won; this one was not selected. Set automatically on award."}]},{"heading":"Detail View Read-Only Fields","items":[{"label":"Part","value":"Entity link to the part plus its number and description. Always shown."},{"label":"Quantity","value":"The quantity needed. Always shown."},{"label":"Required Date","value":"Formatted MM/dd/yyyy. Always shown."},{"label":"Status","value":"The current RFQ status (shown as text in the detail header area)."},{"label":"Response Deadline","value":"Formatted MM/dd/yyyy. Shown only when set."},{"label":"Sent At","value":"Formatted MM/dd/yyyy hh:mm. Shown only after the RFQ has been sent."},{"label":"Awarded At","value":"Formatted MM/dd/yyyy hh:mm. Shown only after award."},{"label":"Generated PO","value":"Entity link to the Purchase Order created on award (PO #id). Shown only after award."},{"label":"Description / Special Instructions / Notes","value":"Free-form text blocks shown only when present; formatting is preserved."}]},{"heading":"Buttons and Actions","items":[{"label":"New RFQ (page header)","value":"Opens the create RFQ dialog. data-testid: new-rfq-btn"},{"label":"Save / Create RFQ (dialog)","value":"Creates (or updates) the RFQ. Disabled when the form is invalid or a save is in progress. data-testid: rfq-save-btn"},{"label":"Send to Vendors (detail)","value":"Opens the vendor multi-select to invite vendors. Available while the RFQ status is Draft or Sent."},{"label":"Record Response (detail)","value":"Opens the form to enter a vendor's quote. Available while the RFQ status is Sent or Receiving."},{"label":"Award (per response)","value":"Awards the RFQ to a vendor's response, sets the RFQ to Awarded, and generates a linked Purchase Order. Available only when the RFQ is not Awarded/Cancelled/Expired and the response status is Received. One-way and irreversible."}]},{"heading":"Validation Rules","items":[{"label":"Part","value":"Required. Must select a part from the dropdown."},{"label":"Quantity","value":"Required, minimum 1."},{"label":"Required Date","value":"Required."},{"label":"Response Deadline, Description, Special Instructions","value":"All optional."},{"label":"Record Response — Vendor","value":"Required. All quote fields (unit price, lead time, MOQ, tooling cost, valid-until, notes) are optional."},{"label":"Create RFQ — Save disabled when","value":"The form is invalid or a save is in progress. Violations are listed in the validation popover on the Save button."}]},{"heading":"RFQ Table Columns","items":[{"label":"RFQ #","value":"Sortable. Auto-generated RFQ number in monospace font."},{"label":"Part","value":"Sortable. The part number."},{"label":"Description","value":"Sortable. The part description."},{"label":"Qty","value":"Sortable. The requested quantity, centered."},{"label":"Status","value":"Sortable, filterable. Color-coded chip: Draft (gray), Sent (blue), Receiving (teal), Evaluating (amber), Awarded (green), Cancelled (red), Expired (gray)."},{"label":"Vendors","value":"Sortable. Count of vendors invited to the RFQ, centered."},{"label":"Received","value":"Sortable. Count of vendors that have responded, centered."},{"label":"Required","value":"Sortable. Required date, formatted MM/dd/yyyy."},{"label":"Deadline","value":"Sortable. Response deadline, formatted MM/dd/yyyy ('—' when not set)."},{"label":"Created","value":"Sortable. Record creation date, formatted MM/dd/yyyy."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Purchasing Knowledge Check",
            Slug = "purchasing-quiz",
            Summary = "Test your knowledge of the Purchasing module: the RFQ lifecycle, inviting vendors, recording responses, comparing quotes, and awarding to generate a Purchase Order.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/purchasing"]""",
            Tags = """["purchasing","rfq","procurement","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"pu1","text":"You need to buy a part and want competitive quotes. How do you start in Purchasing?","options":[{"id":"a","text":"Create a Purchase Order directly and email it to vendors"},{"id":"b","text":"Click New RFQ, select the part, enter the quantity and required date, and save","isCorrect":true},{"id":"c","text":"Go to Vendors and add a quote to each vendor"},{"id":"d","text":"Record a vendor response first; the RFQ is created automatically"}],"explanation":"Start by creating an RFQ. Click New RFQ, pick the part, enter the quantity and required date (optionally a response deadline, description, and special instructions), and save. The RFQ starts in Draft."},{"id":"pu2","text":"What is the correct RFQ lifecycle?","options":[{"id":"a","text":"Open → Quoted → Closed"},{"id":"b","text":"Draft → Sent → Receiving → Evaluating → Awarded","isCorrect":true},{"id":"c","text":"Pending → Approved → Ordered → Received"},{"id":"d","text":"Created → Submitted → Paid"}],"explanation":"An RFQ starts in Draft, moves to Sent when you send it to vendors, then through Receiving and Evaluating as quotes come in and are compared, and finally to Awarded when you pick a winner. Cancelled and Expired are alternate terminal states."},{"id":"pu3","text":"How do you invite vendors to quote an RFQ?","options":[{"id":"a","text":"Add them as line items in the RFQ create dialog"},{"id":"b","text":"Use the Send to Vendors action in the detail, which opens a multi-select of vendors (excluding already-invited ones)","isCorrect":true},{"id":"c","text":"Vendors are invited automatically based on the part"},{"id":"d","text":"Email them manually; the app does not track invitations"}],"explanation":"From the RFQ detail, Send to Vendors opens a multi-select of vendors and excludes any already invited. Sending creates a Pending response for each chosen vendor and moves the RFQ to Sent. It is available while the RFQ is Draft or Sent."},{"id":"pu4","text":"A vendor quotes back. How do you capture their quote?","options":[{"id":"a","text":"Edit the RFQ and overwrite the quantity with the price"},{"id":"b","text":"Use Record Response, select the vendor, and enter unit price, lead time, MOQ, tooling cost, valid-until, and notes","isCorrect":true},{"id":"c","text":"Create a new RFQ for that vendor"},{"id":"d","text":"Award the RFQ first, then enter the price"}],"explanation":"Record Response (available while the RFQ is Sent or Receiving) lets you pick the vendor and enter the quote details. Only the vendor is required; the quote fields are optional. Recording a response marks that vendor's response Received."},{"id":"pu5","text":"On the Record Response form, which vendors can you select?","options":[{"id":"a","text":"Any vendor in the system"},{"id":"b","text":"Only vendors that have a Pending response on this RFQ","isCorrect":true},{"id":"c","text":"Only vendors that have already been awarded"},{"id":"d","text":"Only the preferred vendor for the part"}],"explanation":"The vendor dropdown on Record Response lists only vendors with a Pending response — i.e., vendors who were invited but have not yet had a quote recorded."},{"id":"pu6","text":"What happens when you award an RFQ to a vendor's response?","options":[{"id":"a","text":"Nothing changes until you manually create a PO"},{"id":"b","text":"The RFQ becomes Awarded, the award time is recorded, and a linked Purchase Order is generated","isCorrect":true},{"id":"c","text":"The RFQ is deleted and replaced by the PO"},{"id":"d","text":"All vendors are notified by email automatically"}],"explanation":"Awarding sets the RFQ status to Awarded, records the award timestamp, generates a Purchase Order linked to the RFQ, marks the winning response Awarded and the others Not Awarded, and offers a View PO link."},{"id":"pu7","text":"When is the Award button available for a vendor response?","options":[{"id":"a","text":"Always, for any response"},{"id":"b","text":"Only when the RFQ is not Awarded/Cancelled/Expired and that response's status is Received","isCorrect":true},{"id":"c","text":"Only when the response status is Pending"},{"id":"d","text":"Only after the response deadline has passed"}],"explanation":"Award appears only when the RFQ can still be awarded (not already Awarded, Cancelled, or Expired) and the specific response has been Received — meaning a quote was recorded for it."},{"id":"pu8","text":"Which feature does awarding an RFQ generate?","options":[{"id":"a","text":"A vendor bill"},{"id":"b","text":"A Purchase Order, linked back to the RFQ","isCorrect":true},{"id":"c","text":"A sales order"},{"id":"d","text":"A shipment"}],"explanation":"Awarding is the only action that creates a Purchase Order from an RFQ. The generated PO is linked back to the RFQ and reachable from the View PO link and the Generated PO field."},{"id":"pu9","text":"What is required to save a new RFQ?","options":[{"id":"a","text":"A part, a quantity of at least 1, and a required date","isCorrect":true},{"id":"b","text":"A part, a vendor, and a unit price"},{"id":"c","text":"Only a part"},{"id":"d","text":"A part, a response deadline, and special instructions"}],"explanation":"Required fields are Part, Quantity (minimum 1), and Required Date. Response Deadline, Description, and Special Instructions are optional. Save is disabled until the form is valid."},{"id":"pu10","text":"After you award a winning vendor, what status do the other vendors' responses get?","options":[{"id":"a","text":"They stay Pending"},{"id":"b","text":"They are set to Not Awarded automatically","isCorrect":true},{"id":"c","text":"They are deleted"},{"id":"d","text":"They are set to Declined"}],"explanation":"On award, the winning response becomes Awarded (green) and every other response on the RFQ becomes Not Awarded (amber), set automatically by the award action."},{"id":"pu11","text":"How do you compare vendors before awarding?","options":[{"id":"a","text":"Open each vendor record and check its catalog"},{"id":"b","text":"Review the vendor responses table on the RFQ detail, which lists each quote (price, lead time, MOQ, tooling) side by side","isCorrect":true},{"id":"c","text":"Export the RFQ to a spreadsheet — there is no in-app comparison"},{"id":"d","text":"Comparison is only possible after the PO is created"}],"explanation":"The RFQ detail shows a responses table with each invited vendor's recorded quote — unit price, lead time, MOQ, tooling cost — so you can compare them directly, then award the winner."},{"id":"pu12","text":"What does the 'Received' count column on the RFQ list tell you?","options":[{"id":"a","text":"How many units have been delivered"},{"id":"b","text":"How many of the invited vendors have responded with a quote","isCorrect":true},{"id":"c","text":"How many POs were generated"},{"id":"d","text":"How many days until the deadline"}],"explanation":"The list shows a Vendors count (how many vendors were invited) and a Received count (how many of them have responded). Together they tell you the response progress at a glance."}]}"""
        });

        Log.Information("Seeded Purchasing training modules");
    }
}
